/* Simple JSON string value extractor - handles escape sequences */
static char *json_get_string(const char *json, const char *key) {
    char search[256];
    snprintf(search, sizeof(search), "\"%s\"", key);
    const char *p = strstr(json, search);
    if (!p) return NULL;
    p += strlen(search);
    /* skip whitespace and colon */
    while (*p && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
    if (*p != ':') return NULL;
    p++;
    while (*p && (*p == ' ' || *p == '\t' || *p == '\n' || *p == '\r')) p++;
    if (*p == 'n' && strncmp(p, "null", 4) == 0) return NULL;
    if (*p != '"') return NULL;
    p++; /* skip opening quote */

    /* Parse the string value with escape handling */
    size_t buf_size = 1024;
    char *result = malloc(buf_size);
    size_t j = 0;
    while (*p && *p != '"') {
        if (j + 8 >= buf_size) {
            buf_size *= 2;
            result = realloc(result, buf_size);
        }
        if (*p == '\\') {
            p++;
            switch (*p) {
                case '"': result[j++] = '"'; break;
                case '\\': result[j++] = '\\'; break;
                case '/': result[j++] = '/'; break;
                case 'b': result[j++] = '\b'; break;
                case 'f': result[j++] = '\f'; break;
                case 'n': result[j++] = '\n'; break;
                case 'r': result[j++] = '\r'; break;
                case 't': result[j++] = '\t'; break;
                case 'u': {
                    /* Parse 4 hex digits - store as UTF-8 */
                    unsigned int codepoint = 0;
                    for (int i = 0; i < 4 && p[1]; i++) {
                        p++;
                        codepoint <<= 4;
                        if (*p >= '0' && *p <= '9') codepoint |= *p - '0';
                        else if (*p >= 'a' && *p <= 'f') codepoint |= *p - 'a' + 10;
                        else if (*p >= 'A' && *p <= 'F') codepoint |= *p - 'A' + 10;
                    }
                    if (codepoint < 0x80) {
                        result[j++] = (char)codepoint;
                    } else if (codepoint < 0x800) {
                        result[j++] = (char)(0xC0 | (codepoint >> 6));
                        result[j++] = (char)(0x80 | (codepoint & 0x3F));
                    } else {
                        result[j++] = (char)(0xE0 | (codepoint >> 12));
                        result[j++] = (char)(0x80 | ((codepoint >> 6) & 0x3F));
                        result[j++] = (char)(0x80 | (codepoint & 0x3F));
                    }
                    break;
                }
                default: result[j++] = *p; break;
            }
        } else {
            result[j++] = *p;
        }
        p++;
    }
    result[j] = '\0';
    return result;
}

