    return strstr(json, search) != NULL;
}

static int parse_id_from_url(const char *url) {
    /* url is like /api/notes/123 */
    const char *p = url + strlen("/api/notes/");
    if (*p == '\0') return -1;
    /* Check all chars are digits */
    for (const char *c = p; *c; c++) {
        if (!isdigit((unsigned char)*c)) return -1;
    }
    return atoi(p);
}

enum MHD_Result route_request(struct MHD_Connection *connection, const char *url,
                              const char *method, const char *upload_data,
                              size_t *upload_data_size, void **con_cls) {

    /* Handle connection data accumulation for POST/PUT */
    if (*con_cls == NULL) {
        struct connection_info *ci = calloc(1, sizeof(struct connection_info));
        if (!ci) return MHD_NO;
        ci->data = NULL;
        ci->data_size = 0;
        *con_cls = ci;
        return MHD_YES; /* Wait for data */
    }

    struct connection_info *ci = *con_cls;

    /* Accumulate upload data */
    if (*upload_data_size > 0) {
        /* Check body size limit */
        if (ci->data_size + *upload_data_size > MAX_BODY) {
            *upload_data_size = 0;
            ci->data_size = MAX_BODY + 1; /* Mark as too large */
            return MHD_YES;
        }
        char *new_data = realloc(ci->data, ci->data_size + *upload_data_size + 1);
        if (!new_data) return MHD_NO;
        memcpy(new_data + ci->data_size, upload_data, *upload_data_size);
        ci->data_size += *upload_data_size;
        new_data[ci->data_size] = '\0';
        ci->data = new_data;
        *upload_data_size = 0;
        return MHD_YES;
    }

    /* All data received, process the request */

    /* OPTIONS preflight */
    if (strcmp(method, "OPTIONS") == 0) {
        return send_json(connection, "", MHD_HTTP_NO_CONTENT);
    }

    /* Check body size exceeded */
    if (ci->data_size > MAX_BODY) {
        return send_json(connection, "{\"error\":\"body too large\"}", MHD_HTTP_PAYLOAD_TOO_LARGE);
    }

    /* Route: GET /api/notes */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "GET") == 0) {
        const char *limit_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit");
        const char *offset_str = MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset");
        int limit = NOTES_DEFAULT_PAGE_SIZE;
        int offset = 0;
        if (limit_str) limit = atoi(limit_str);
        if (offset_str) offset = atoi(offset_str);
        if (limit <= 0) limit = NOTES_DEFAULT_PAGE_SIZE;
        if (limit > NOTES_MAX_PAGE_SIZE) limit = NOTES_MAX_PAGE_SIZE;
        if (offset < 0) offset = 0;

        int total = get_total_notes_count();
        char *json = get_notes_paginated_json(limit, offset);
        if (!json) json = strdup("[]");
        enum MHD_Result r = send_json_response(connection, json, MHD_HTTP_OK, total);
        free(json);
        return r;
    }

    /* Route: POST /api/notes */
    if (strcmp(url, "/api/notes") == 0 && strcmp(method, "POST") == 0) {
        if (!api_key_valid(connection)) {
            return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
        }
        if (!ci->data || ci->data_size == 0) {
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        char *title = json_get_string(ci->data, "title");
        if (!title || strlen(title) == 0) {
            free(title);
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        /* Check title is not just whitespace */
        int all_space = 1;
        for (size_t i = 0; title[i]; i++) {
            if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
        }
        if (all_space) {
            free(title);
            return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
        }
        char *content = json_get_string(ci->data, "content");
        int id = create_note(title, content ? content : "");
        if (id < 0) {
            free(title); free(content);
            return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
        }
        char *note_json = get_note_json(id);
        enum MHD_Result r = send_json(connection, note_json, MHD_HTTP_CREATED);
        free(note_json);
        free(title); free(content);
        return r;
    }

    /* Routes with ID: /api/notes/{id} */
    if (strncmp(url, "/api/notes/", 11) == 0 && strlen(url) > 11) {
        int id = parse_id_from_url(url);
        if (id < 0) {
            return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
        }

        /* GET /api/notes/{id} */
        if (strcmp(method, "GET") == 0) {
            char *json = get_note_json(id);
            if (!json) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        /* PUT /api/notes/{id} */
        if (strcmp(method, "PUT") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            if (!ci->data || ci->data_size == 0) {
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            char *title = json_get_string(ci->data, "title");
            if (!title || strlen(title) == 0) {
                free(title);
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            int all_space = 1;
            for (size_t i = 0; title[i]; i++) {
                if (!isspace((unsigned char)title[i])) { all_space = 0; break; }
            }
            if (all_space) {
                free(title);
                return send_json(connection, "{\"error\":\"title is required\"}", MHD_HTTP_BAD_REQUEST);
            }
            char *content = json_get_string(ci->data, "content");
            int result = update_note(id, title, content ? content : "");
            free(title); free(content);
            if (result == 1) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            if (result < 0) {
                return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            char *json = get_note_json(id);
            enum MHD_Result r = send_json(connection, json, MHD_HTTP_OK);
            free(json);
            return r;
        }

        /* DELETE /api/notes/{id} */
        if (strcmp(method, "DELETE") == 0) {
            if (!api_key_valid(connection)) {
                return send_json(connection, "{\"error\":\"unauthorized\"}", MHD_HTTP_UNAUTHORIZED);
            }
            int result = delete_note(id);
            if (result == 1) {
                return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
            }
            if (result < 0) {
                return send_json(connection, "{\"error\":\"server error\"}", MHD_HTTP_INTERNAL_SERVER_ERROR);
            }
            return send_json(connection, "{\"status\":\"deleted\"}", MHD_HTTP_OK);
        }
    }

    return send_json(connection, "{\"error\":\"not found\"}", MHD_HTTP_NOT_FOUND);
}
